class Solution {
public:
    long long countMajoritySubarrays(vector<int>& nums, int target) {
        int n = nums.size();
        vector<int> freq(2 * n + 1, 0);
        freq[n] = 1;
        int idx = n;
        long long res = 0;
        long long pref = 0;
        for (int x : nums) {
            if (x == target) {
                pref += freq[idx];
                idx++;
            } else {
                idx--;
                pref -= freq[idx];
            }
            freq[idx]++;
            res += pref;
        }
        return res;
    }
};

class Solution {
public:
    long long countMajoritySubarrays(vector<int>& nums, int target) {
        long long v = 0;
        for( int i = 0; i < nums.size(); i++){
            int sum =0;
            for( int j = i ; j< nums.size();j++){
                sum += (nums[j]==target)? 1:-1;
                if( sum > 0) v++;
            }
        }
        return v;
    }
};

class Solution {
public:
    bool isOneBitCharacter(vector<int>& bits) {
        int i = 0;
        int n = bits.size();

        while (i < n - 1) {
            if (bits[i] == 0)
                i += 1;
            else
                i += 2;
        }

        return i == n - 1;
    }
};

